export type TimeEntryInsert          = TablesInsert<'time_entries'>;
export type ReportAuditLogInsert     = TablesInsert<'report_audit_log'>;

// ── Composite / joined types (not generated by supabase gen types) ───────────

export type OrderWithItems = OrderRow & {
  order_items: OrderItemRow[];
  branch: BranchRow | null;
};

export type ShiftWithStaff = ShiftRow & {
  staff_basic: Pick<StaffBasicRow, 'name' | 'role'>;
};

export type KDSQueueItem = KDSQueueRow & {
  order_items: Pick<OrderItemRow, 'name_ar' | 'name_en' | 'quantity' | 'selected_size' | 'selected_variant'>;
  orders: Pick<OrderRow, 'customer_name' | 'notes' | 'branch_id' | 'status' | 'created_at'>;
};

export type KDSOrder = Omit<OrderRow, 'status'> & {
  status: 'accepted' | 'preparing' | 'ready';
  order_items: Array<{
    id: string;
    name_ar: string;
    name_en: string;
    quantity: number;
    selected_size: string | null;
    selected_variant: string | null;
  }>;
};

export type DriverOrder = OrderRow & {
  order_items: Pick<OrderItemRow, 'name_ar' | 'name_en' | 'quantity' | 'selected_size' | 'selected_variant'>[];
  payments?: { method: PaymentMethod } | null;
  cash_settlement?: Array<{ handover_id: string }> | null;
  // Added by migration 037 — manually typed until types.ts is regenerated
  cash_settled_at?: string | null;
  cash_settlement_id?: string | null;
  // Added by migration 040
  tip_bhd?: number | null;
};

// Re-narrow `audit_logs.action` for safer call sites — the column is a generic
// `string` in Postgres but only ever holds one of three values in practice.
export type TypedAuditLogRow = Omit<AuditLogRow, 'action'> & { action: AuditLogAction };
